package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringWriter;
import java.lang.reflect.Field;
import java.lang.reflect.Modifier;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.QuoteMode;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    private CSVFormat csvFormatDefault;
    private CSVFormat csvFormatNoQuote;
    private CSVFormat csvFormatCustom;

    @BeforeEach
    public void setup() {
        csvFormatDefault = CSVFormat.DEFAULT;
        csvFormatNoQuote = CSVFormat.DEFAULT.withQuote((Character) null);
        csvFormatCustom = CSVFormat.newFormat(';').withQuote('\'').withQuoteMode(QuoteMode.ALL);
    }

    @Test
    public void testFormat_withNormalValues() {
        String result = csvFormatDefault.format("a", "b", "c");
        assertEquals("a,b,c", result);
    }

    @Test
    public void testFormat_withNullValue() {
        CSVFormat format = CSVFormat.DEFAULT.withNullString("NULL");
        String result = format.format("a", null, "c");
        assertEquals("a,NULL,c", result);
    }

    @Test
    public void testFormat_withEmptyValues() {
        String result = csvFormatDefault.format();
        assertEquals("", result);
    }

    @Test
    public void testFormat_withNoQuoteCharacter() {
        String result = csvFormatNoQuote.format("a,b", "c");
        assertEquals("a,b,c", result);
    }

    @Test
    public void testFormat_withCustomDelimiterAndQuote() {
        String result = csvFormatCustom.format("a;b", "b;c");
        // Values quoted due to QuoteMode.ALL and quote char '\''
        assertEquals("'a;b';'b;c'", result);
    }

    @Test
    public void testFormat_throwsIllegalStateExceptionOnIOException() throws Exception {
        // Create a CSVFormat instance with the same properties as DEFAULT, but override format method via proxy
        CSVFormat format = new CSVFormatProxy(CSVFormat.DEFAULT);

        IllegalStateException thrown = assertThrows(IllegalStateException.class, () -> {
            format.format("test");
        });
        assertTrue(thrown.getCause() instanceof IOException);
        assertEquals("IO error", thrown.getCause().getMessage());
    }

    // Helper subclass to override format method to simulate IOException
    private static class CSVFormatProxy extends CSVFormat {
        private final CSVFormat delegate;

        CSVFormatProxy(CSVFormat delegate) throws Exception {
            super(getFieldChar(delegate, "delimiter"),
                  getFieldCharacter(delegate, "quoteCharacter"),
                  getFieldQuoteMode(delegate, "quoteMode"),
                  getFieldCharacter(delegate, "commentMarker"),
                  getFieldCharacter(delegate, "escapeCharacter"),
                  getFieldBoolean(delegate, "ignoreSurroundingSpaces"),
                  getFieldBoolean(delegate, "ignoreEmptyLines"),
                  getFieldString(delegate, "recordSeparator"),
                  getFieldString(delegate, "nullString"),
                  getFieldStringArray(delegate, "headerComments"),
                  getFieldStringArray(delegate, "header"),
                  getFieldBoolean(delegate, "skipHeaderRecord"),
                  getFieldBoolean(delegate, "allowMissingColumnNames"),
                  getFieldBoolean(delegate, "ignoreHeaderCase"));
            this.delegate = delegate;
        }

        @Override
        public String format(final Object... values) {
            try {
                throw new IOException("IO error");
            } catch (IOException e) {
                throw new IllegalStateException(e);
            }
        }

        // Reflection helpers
        private static char getFieldChar(CSVFormat obj, String fieldName) throws Exception {
            Field f = CSVFormat.class.getDeclaredField(fieldName);
            f.setAccessible(true);
            return f.getChar(obj);
        }

        private static Character getFieldCharacter(CSVFormat obj, String fieldName) throws Exception {
            Field f = CSVFormat.class.getDeclaredField(fieldName);
            f.setAccessible(true);
            return (Character) f.get(obj);
        }

        private static QuoteMode getFieldQuoteMode(CSVFormat obj, String fieldName) throws Exception {
            Field f = CSVFormat.class.getDeclaredField(fieldName);
            f.setAccessible(true);
            return (QuoteMode) f.get(obj);
        }

        private static boolean getFieldBoolean(CSVFormat obj, String fieldName) throws Exception {
            Field f = CSVFormat.class.getDeclaredField(fieldName);
            f.setAccessible(true);
            return f.getBoolean(obj);
        }

        private static String getFieldString(CSVFormat obj, String fieldName) throws Exception {
            Field f = CSVFormat.class.getDeclaredField(fieldName);
            f.setAccessible(true);
            return (String) f.get(obj);
        }

        private static String[] getFieldStringArray(CSVFormat obj, String fieldName) throws Exception {
            Field f = CSVFormat.class.getDeclaredField(fieldName);
            f.setAccessible(true);
            return (String[]) f.get(obj);
        }
    }
}
